.shape-sort-board {
  min-height: 360px;
  padding: 16px;
}

.shape-tile {
  width: 72px;
  height: 72px;
  border-radius: 18px;
}

/* Mobile: enlarge drag targets to meet 44 px minimum touch-target guidelines */
@media (pointer: coarse) {
  .shape-tile {
    width: 96px;
    height: 96px;
    border-radius: 24px;
    touch-action: none; /* prevent scroll interference during drag */
  }
}

